-- ---------------------------------------------------------- Tabel structuur voor tabel gebruikgeschtabel-- --------------------------------------------------------DROP TABLE IF EXISTS gebruikgeschtabel;CREATE TABLE gebruikgeschtabel (persoon_id smallint(11) NOT NULL,eersteleeft smallint(3) default NULL,-- toen je voor het eerst alcohol dronkbevieleerste smallint(3) default NULL,-- beviel eerste kennismaking? 1= beviel niet echt 2= was wel aardig 3=voelde gelijk geweldigeerstekader smallint(3) default NULL,-- in het kader van  1=experiment / uitproberen hoe dat is 2=met een bepaald doel voor ogen 3=ik herinner mij dat niet echt meer 4=ik voelde mij gedwongenaanloop smallint(3) default NULL,-- verloop 3=vanaf eerste moment meer gedronken dan gemiddeld 2=ik ben gaandeweg meer gaan drinken 1=het was later dat ik teveel ben gaan drinkentoegeefjaar smallint(6) default NULL,-- kalender jaar controle verliesverlooppatroon smallint(3) default NULL,-- patronen nog doen: bijv 1= kicks/sociaal 2=bij problmen  3=gemiddeldeweek smallint(5) default NULL,-- aantallen eenheden/weekomgevingzorg smallint(3) default NULL,-- omgeving: 0=nee, niemand 1=een enkeling 2=dat heb ik wel vaker gehoordstoppogingen smallint(3) default NULL,-- pogingen ooit 0=nee, nooit 1=wel eens 2=een paar serieuze 3=vaakPRIMARY KEY (persoon_id)-- KEY partner_id (partner_id)) TYPE=MyISAM AUTO_INCREMENT=1 ;-- Gegevens worden uitgevoerd voor tabel gebruikgeschtabelINSERT INTO gebruikgeschtabel VALUES (2, 16, 2, 1, 1, 1991, 0, 28, 1, 1);
